import base64
from PIL import Image, ImageDraw
import io
import streamlit as st

# ---------------- CONFIG ---------------- #
A4_WIDTH = 2480
A4_HEIGHT = 3508

COLS = 2
ROWS = 4
IMAGES_PER_PAGE = COLS * ROWS


# ---------------- STATE ---------------- #
st.set_page_config(layout="wide")

LOGO_BASE64 = """

"""

def render_header():
    logo_bytes = base64.b64decode(LOGO_BASE64)
    image = Image.open(io.BytesIO(logo_bytes))

    col1, col2 = st.columns([0.12, 0.88], vertical_alignment="center")

    with col1:
        st.image(image, width=70)

    with col2:
        st.markdown(
            """
            <div style="
                display:flex;
                align-items:center;
                height:70px;
            ">
                <div>
                    <h2 style="margin:0; padding:0;">
                        Paparazzi A4 Combiner
                    </h2>
                    <div style="color:gray; font-size:12px; margin-top:2px;">
                        Create printable A4 image sheets
                    </div>
                </div>
            </div>
            """,
            unsafe_allow_html=True
        )

render_header()


if "images" not in st.session_state:
    st.session_state.images = []

if "page" not in st.session_state:
    st.session_state.page = 0

if "margin" not in st.session_state:
    st.session_state.margin = 0

if "uploader_key" not in st.session_state:
    st.session_state.uploader_key = 0


# ---------------- UPLOAD (RESETTABLE) ---------------- #
uploaded = st.file_uploader(
    "Upload images",
    type=["png", "jpg", "jpeg"],
    accept_multiple_files=True,
    key=f"uploader_{st.session_state.uploader_key}"
)

if uploaded:
    for file in uploaded:
        data = file.read()

        # prevent duplicates by raw bytes
        if not any(img["data"] == data for img in st.session_state.images):
            st.session_state.images.append({"data": data})


# ---------------- RESET BUTTON (THIS FIXES EVERYTHING) ---------------- #
if st.button("🗑 Reset Uploads"):
    st.session_state.images = []
    st.session_state.page = 0
    st.session_state.uploader_key += 1  # 🔥 forces uploader reset
    st.rerun()


# ---------------- IMAGE FIT ---------------- #
def fit_inside(img, tw, th):
    img = img.convert("RGB")
    img.thumbnail((tw, th))

    canvas = Image.new("RGB", (tw, th), "white")

    x = (tw - img.width) // 2
    y = (th - img.height) // 2

    canvas.paste(img, (x, y))
    return canvas


# ---------------- PAGE GENERATION ---------------- #
def generate_page(page, draw_boxes=True):
    margin = st.session_state.margin

    cell_w = (A4_WIDTH - (COLS - 1) * margin) // COLS
    cell_h = (A4_HEIGHT - (ROWS - 1) * margin) // ROWS

    canvas = Image.new("RGB", (A4_WIDTH, A4_HEIGHT), "white")
    draw = ImageDraw.Draw(canvas)

    start = page * IMAGES_PER_PAGE
    items = st.session_state.images[start:start + IMAGES_PER_PAGE]

    for i in range(IMAGES_PER_PAGE):
        col = i % COLS
        row = i // COLS

        x0 = col * (cell_w + margin)
        y0 = row * (cell_h + margin)

        if i < len(items):
            img = Image.open(io.BytesIO(items[i]["data"]))
            img = fit_inside(img, cell_w, cell_h)
            canvas.paste(img, (x0, y0))

        if draw_boxes:
            draw.rectangle(
                [x0, y0, x0 + cell_w, y0 + cell_h],
                outline="black",
                width=2
            )

    return canvas


# ---------------- PAGE COUNT ---------------- #
def get_pages():
    if not st.session_state.images:
        return 1
    return (len(st.session_state.images) - 1) // IMAGES_PER_PAGE + 1


# ---------------- MARGIN ---------------- #
st.number_input(
    "Margin (px)",
    min_value=0,
    max_value=200,
    step=10,
    key="margin"
)

pages = get_pages()

# Main layout: center preview + right export
col_left, col_mid, col_right = st.columns([1, 2, 1])


# ---------------- CENTER COLUMN ---------------- #
with col_mid:

    # --- NAVIGATION (NOW PERFECTLY ALIGNED) --- #
    nav1, nav2, nav3 = st.columns([1.5, 2, 2], vertical_alignment="center")

    with nav1:
        if st.button("⬅ Prev"):
            if st.session_state.page > 0:
                st.session_state.page -= 1
                st.rerun()

    with nav2:
        st.markdown(
            f"""
            <div style="
                display:flex;
                justify-content:center;
                align-items:center;
                height:38px;
                font-weight:500;
            ">
                Page {st.session_state.page + 1} / {pages}
            </div>
            """,
            unsafe_allow_html=True
        )

    with nav3:
        if st.button("Next ➡"):
            if st.session_state.page < pages - 1:
                st.session_state.page += 1
                st.rerun()

    # --- PREVIEW --- #
    def generate_preview(page):
        full = generate_page(page, draw_boxes=True)
        preview = full.copy()
        preview.thumbnail((381, 540))
        return preview

    if st.session_state.images:
        preview = generate_preview(st.session_state.page)
        st.image(preview)

    else:
        st.info("Upload images to begin")


# ---------------- RIGHT COLUMN (EXPORT) ---------------- #
with col_right:
    if st.session_state.images:

        def export_pdf():
            pages_list = []
            for p in range(get_pages()):
                pages_list.append(generate_page(p, draw_boxes=False))

            buf = io.BytesIO()
            pages_list[0].save(
                buf,
                format="PDF",
                save_all=True,
                append_images=pages_list[1:],
                resolution=300
            )
            buf.seek(0)
            return buf

        pdf = export_pdf()

        st.download_button(
            "📥 Download PDF",
            pdf,
            file_name="a4_export.pdf",
            mime="application/pdf"
        )